class CreditSupportObligationsLegacy(CreditSupportObligationsBase):
    """
    Specification of the Credit Support Obligations applicable to the Legacy (1994/95) Credit Support Annex.
    """

    _id_name : str = None
    threshold: Struct = pla.Field()
    """
    Represents the amount of unsecured risk that a party is willing to tolerate without holding any posted collateral provided by the other party.
    """
    
    rounding: Struct = pla.Field()
    """
    The rounding methodology applicable to the Delivery Amount and the Return Amount in terms of nearest integral multiple of Base Currency units.
    """
    
    independentAmount: Struct = pla.Field()
    """
    Specifies the additional amount of collateral that is required to be delivered by a party irrespective of the mark-to-market exposure under the related Transactions. It may take the form of a fixed amount or may be determined using ratings.
    """
    
    creditSupportAmount: Struct = pla.Field()
    """
    The total amount one counterparty must deliver to the other at any time: the combination of the Exposure to that party and the net Independent Amounts it must post, minus any agreed Threshold.
    """
    
    eligibleCreditSupport: Struct = pla.Field()
    """
    Specification of the Eligible Collateral or Credit Support applicable to the Agreement.
    """
    
    
    @pla.check("threshold")
    def check_nested_struct_threshold(cls, data: PolarsData):
        
        return cls._check_nested_struct(data, Threshold, pa_pl.Threshold)
        
    @pla.check("rounding")
    def check_nested_struct_rounding(cls, data: PolarsData):
        
        return cls._check_nested_struct(data, CollateralRounding, pa_pl.CollateralRounding)
        
    @pla.check("independentAmount")
    def check_nested_struct_independentAmount(cls, data: PolarsData):
        
        return cls._check_nested_struct(data, LegacyIndependentAmount, pa_pl.LegacyIndependentAmount)
        
    @pla.check("creditSupportAmount")
    def check_nested_struct_creditSupportAmount(cls, data: PolarsData):
        
        return cls._check_nested_struct(data, CreditSupportAmount, pa_pl.CreditSupportAmount)
        
    @pla.check("eligibleCreditSupport")
    def check_nested_struct_eligibleCreditSupport(cls, data: PolarsData):
        
        return cls._check_nested_struct(data, EligibleCreditSupport, pa_pl.EligibleCreditSupport)
        
