    @pla.check("pricingDates")
    def check_nested_struct_pricingDates(cls, data: PolarsData):
        
        return cls._check_nested_struct(data, PricingDates, pa_pl.PricingDates)
        
    @pla.check("schedule")
    def check_nested_struct_schedule(cls, data: PolarsData):
        
        return cls._check_nested_struct(data, CalculationSchedule, pa_pl.CalculationSchedule)
        
    @pla.check("calculationPeriodDates")
    def check_nested_struct_calculationPeriodDates(cls, data: PolarsData):
        
        return cls._check_nested_struct(data, CalculationPeriodDates, pa_pl.CalculationPeriodDates)
        
